sql:
SELECT AVG(d.delivery_fee) AS average_delivery_fee
FROM deliveries d
WHERE d.restaurant_id = 0;

SELECT COUNT(*) AS number_of_bookings
FROM bookings
WHERE user_id = 0;

SELECT delivery_id
FROM deliveries
WHERE delivery_id = 0;

